    </div>
}
else
{
    <div class="d-flex flex-row gap-4">
        <!-- Sidebar filters -->
        <div style="min-width: 250px; flex: 0 0 25%;">
            <div class="card">
                <div class="card-header fw-bold">Filters</div>
                <div class="card-body">
                    @if (_categories is not null)
                    {
                        <h6>Category</h6>
                        <div class="mb-3">
                            @foreach (var category in _categories)
                            {
                                <div class="form-check">
                                    <input class="form-check-input" type="checkbox" id="@($"cat-{category}")"
                                           checked="@(_selectedCategories.Contains(category))"
                                           @onchange="e => ToggleCategory(category, (bool)e.Value!)" />
                                    <label class="form-check-label" for="@($"cat-{category}")">@category</label>
                                </div>
                            }
                        </div>
                    }

                    <h6>Price Range</h6>
                    <div class="row g-2 mb-3">
                        <div class="col-6">
                            <input type="number" class="form-control form-control-sm" placeholder="Min"
                                   value="@_minPrice" @onchange="e => _minPrice = ParseDecimal(e.Value)" />
                        </div>
                        <div class="col-6">
                            <input type="number" class="form-control form-control-sm" placeholder="Max"
                                   value="@_maxPrice" @onchange="e => _maxPrice = ParseDecimal(e.Value)" />
                        </div>
                    </div>

                    <div class="form-check mb-3">
                        <input class="form-check-input" type="checkbox" id="inStockOnly"
                               checked="@_inStockOnly"
                               @onchange="e => _inStockOnly = (bool)e.Value!" />
                        <label class="form-check-label" for="inStockOnly">In Stock Only</label>
                    </div>

                    <div class="d-grid gap-2">
                        <button class="btn btn-primary btn-sm" @onclick="ApplyFiltersAsync">Apply Filters</button>
                        <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFiltersAsync">Clear Filters</button>
                    </div>
                </div>
            </div>
        </div>

        <!-- Main content -->
        <div style="flex: 1 1 75%;">
            @if (_loading)
            {
                <div class="d-flex justify-content-center align-items-center py-5">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading...</span>
                    </div>
                    <span class="ms-2">Loading products...</span>
                </div>
            }
            else if (_result is not null)
            {
                <!-- Toolbar -->
                <div class="d-flex justify-content-between align-items-center mb-3">
                    <div>
                        <label class="form-label me-2 mb-0" for="sortSelect">Sort by:</label>
                        <select id="sortSelect" class="form-select form-select-sm d-inline-block w-auto"
                                value="@_sortBy" @onchange="SortChangedAsync">
                            <option value="price_asc">Price: Low to High</option>
                            <option value="price_desc">Price: High to Low</option>
                            <option value="name_asc">Name: A-Z</option>
                            <option value="rating_desc">Rating: Highest</option>
                        </select>
                    </div>
                    <span class="text-muted">
                        @if (_result.TotalCount > 0)
                        {
                            var first = (_result.Page - 1) * _result.PageSize + 1;
                            var last = Math.Min(_result.Page * _result.PageSize, _result.TotalCount);
                            <text>Showing @first–@last of @_result.TotalCount products</text>
                        }
                        else
                        {
                            <text>No products found</text>
                        }
                    </span>
                </div>

                @if (_result.Items.Count == 0)
                {
                    <div class="alert alert-info text-center">
                        No products match your filters. Try adjusting your criteria.
                    </div>
                }
                else
                {
                    <!-- Product grid -->
                    <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4 mb-4">
                        @foreach (var product in _result.Items)
                        {
                            <div class="col">
                                <ProductCard Product="product"
                                             OnProductSelected="HandleProductSelected"
                                             OnAddToCart="HandleAddToCart" />
                            </div>
                        }
                    </div>

